set check_function_bodies = off;
set client_min_messages = warning;


-- file: views/stats_team_book_alltime.sql
-- Per-user, two-sided TEAM BOOK at CAREER grain (all seasons pooled) -- the all-time sibling of
-- stats_team_book (issue #564). Same backed/faded re-projection: every settled, placed pick in a
-- scoring round emits one BACKED row (picked team) and one FADED row (opponent) off the same
-- outcome, so the career book shows both who the player most reliably rides and who they most
-- reliably fade across every season they've played.
--
-- Career-first because the signature strip and standouts lead the page (#564): per-season fade
-- samples are often too thin to trust, but pooled across the imported 2022-24 seasons a fade
-- record has real weight. accuracy = wins / (wins + losses), pushes excluded, 4 dp -- identical
-- math to stats_team_book so the two scopes read the same.
--
-- Guards mirror stats_team_book exactly: non-scoring rounds excluded (w.is_scoring), placed picks
-- only (ps.pick_id is not null). Materialized, service-role-only (ADR-0013); group_id leads the
-- unique index (ADR-0002). Reads only base tables, so no cascade re-touch on re-emit.
-- DROP MATERIALIZED VIEW (not DROP VIEW): re-emission runs against an existing matview.
drop materialized view if exists public.stats_team_book_alltime;

create materialized view public.stats_team_book_alltime as
with settled as (
  select
    ps.group_id,
    ps.user_id,
    u.display_name,
    ps.outcome,
    ps.points_delta,
    p.picked_team_id,
    case when p.picked_team_id = g.home_team_id then g.away_team_id else g.home_team_id end
      as opponent_team_id
  from public.pick_settlement ps
  join public.picks p on p.id = ps.pick_id
  join public.games g on g.id = ps.game_id
  join public.weeks w on w.id = g.week_id
  join public.users u on u.id = ps.user_id
  where w.is_scoring
    and ps.pick_id is not null
),
sided as (
  select group_id, user_id, display_name,
    'backed'::text as side, picked_team_id as team_id, outcome, points_delta
  from settled
  union all
  select group_id, user_id, display_name,
    'faded'::text as side, opponent_team_id as team_id, outcome, points_delta
  from settled
)
select
  sd.user_id,
  sd.display_name,
  sd.side,
  sd.team_id,
  t.name as team_name,
  t.short_name as team_short_name,
  count(*)::int as decisions,
  count(*) filter (where sd.outcome = 'win')::int as wins,
  count(*) filter (where sd.outcome = 'loss')::int as losses,
  count(*) filter (where sd.outcome = 'push')::int as pushes,
  sum(sd.points_delta)::int as points,
  round(
    count(*) filter (where sd.outcome = 'win')::numeric
      / nullif(count(*) filter (where sd.outcome in ('win', 'loss')), 0),
    4
  ) as accuracy,
  sd.group_id
from sided sd
join public.teams t on t.id = sd.team_id
group by sd.user_id, sd.display_name, sd.side, sd.team_id, t.name, t.short_name, sd.group_id;

-- Unique natural key for REFRESH ... CONCURRENTLY; group_id leads per ADR-0002.
create unique index if not exists uq_stats_team_book_alltime
  on public.stats_team_book_alltime (group_id, user_id, side, team_id);

revoke all on public.stats_team_book_alltime from public, anon, authenticated;
grant select on public.stats_team_book_alltime to service_role;

-- file: views/stats_team_book.sql
-- Per-user, two-sided TEAM BOOK at SEASON grain (issue #564): for every team, the player's ATS
-- record when they BACKED that team (picked it to cover) and when they FADED it (picked its
-- opponent). This adds the "teams you bet against" half stats_accuracy_by_team never had -- that
-- view stores picked_team_id only, so it can describe who you ride but never who you fade.
--
-- Every settled, placed pick in a scoring round emits exactly TWO rows off the same outcome:
--   backed -> (team = picked_team_id)   -- your record riding that team
--   faded  -> (team = the opponent)     -- your record betting against that team
-- so a 9-game slate becomes 18 sided rows before aggregation. The opponent is simply the game's
-- other side (picked_team_id is always the home or away team). "faded" is a pure re-projection of
-- data the pick already carries -- no schema change, no re-grade.
--
-- accuracy = wins / (wins + losses), pushes excluded, 4 dp, matching stats_accuracy_by_team so ATS
-- win% reads the same everywhere; on a faded row that is the player's cover rate AGAINST the team.
-- Non-scoring rounds (ADR-0016) never count (w.is_scoring); missed picks carry no team, so only
-- placed picks count (ps.pick_id is not null) -- the same guards stats_situational_base uses.
--
-- Materialized (ADR-0013): matviews can't carry RLS, so all reads are service-role-only; the
-- unique index leads on group_id (ADR-0002) and is required for REFRESH ... CONCURRENTLY. Reads
-- only base tables (no view dependency), so re-emitting this file needs no cascade re-touch.
-- DROP MATERIALIZED VIEW (not DROP VIEW): re-emission runs against an existing matview.
drop materialized view if exists public.stats_team_book;

create materialized view public.stats_team_book as
with settled as (
  select
    ps.group_id,
    ps.user_id,
    u.display_name,
    s.year as season_year,
    ps.outcome,
    ps.points_delta,
    p.picked_team_id,
    -- The opponent = the game's other side; picked_team_id is always home or away.
    case when p.picked_team_id = g.home_team_id then g.away_team_id else g.home_team_id end
      as opponent_team_id
  from public.pick_settlement ps
  join public.picks p on p.id = ps.pick_id
  join public.games g on g.id = ps.game_id
  join public.weeks w on w.id = g.week_id
  join public.seasons s on s.id = w.season_id
  join public.users u on u.id = ps.user_id
  -- Non-scoring rounds (ADR-0016) never count; missed picks carry no team.
  where w.is_scoring
    and ps.pick_id is not null
),
sided as (
  select group_id, user_id, display_name, season_year,
    'backed'::text as side, picked_team_id as team_id, outcome, points_delta
  from settled
  union all
  select group_id, user_id, display_name, season_year,
    'faded'::text as side, opponent_team_id as team_id, outcome, points_delta
  from settled
)
select
  sd.user_id,
  sd.display_name,
  sd.season_year,
  sd.side,
  sd.team_id,
  t.name as team_name,
  t.short_name as team_short_name,
  count(*)::int as decisions,
  count(*) filter (where sd.outcome = 'win')::int as wins,
  count(*) filter (where sd.outcome = 'loss')::int as losses,
  count(*) filter (where sd.outcome = 'push')::int as pushes,
  sum(sd.points_delta)::int as points,
  round(
    count(*) filter (where sd.outcome = 'win')::numeric
      / nullif(count(*) filter (where sd.outcome in ('win', 'loss')), 0),
    4
  ) as accuracy,
  sd.group_id
from sided sd
join public.teams t on t.id = sd.team_id
group by sd.user_id, sd.display_name, sd.season_year, sd.side, sd.team_id,
  t.name, t.short_name, sd.group_id;

-- Unique natural key for REFRESH ... CONCURRENTLY; group_id leads per ADR-0002. side is part of
-- the key because a team can appear once backed and once faded per (user, season).
create unique index if not exists uq_stats_team_book
  on public.stats_team_book (group_id, user_id, season_year, side, team_id);

revoke all on public.stats_team_book from public, anon, authenticated;
grant select on public.stats_team_book to service_role;

-- file: functions/stats/refresh_leaderboard_stats.sql
-- Refresh the materialized leaderboard/stats views after a grading run (issue #191).
--
-- SECURITY DEFINER so it executes as the matview owner (postgres) -- REFRESH MATERIALIZED
-- VIEW requires ownership, and the calling service_role is not the owner. search_path is
-- pinned empty with every object schema-qualified.
--
-- CONCURRENTLY keeps each view readable by in-flight requests during the refresh and is
-- transaction-safe inside this function (unlike CREATE INDEX CONCURRENTLY, REFRESH ...
-- CONCURRENTLY does not self-manage transactions); it requires the unique index each
-- matview declares in supabase/src/views/.
--
-- Called by the server grading helpers (src/lib/server/grading.ts) after grade_game /
-- grade_week / grade_season succeed. A refresh failure is logged there but does NOT fail
-- the grade: the settlement write already committed and a stale matview self-heals on the
-- next grade. EXECUTE is granted to service_role by grants/admin_grants.sql (blanket
-- grant on all functions); the closed-by-default ACL guard strips only the PUBLIC grant.
create or replace function public.refresh_leaderboard_stats()
returns void
language plpgsql
security definer
set search_path = ''
as $$
begin
  refresh materialized view concurrently public.leaderboard_season_totals;
  refresh materialized view concurrently public.stats_season_trend;
  refresh materialized view concurrently public.stats_accuracy_by_team;
  refresh materialized view concurrently public.stats_accuracy_by_weight;
  refresh materialized view concurrently public.stats_head_to_head;
  refresh materialized view concurrently public.stats_head_to_head_alltime;
  refresh materialized view concurrently public.stats_alltime_totals;
  refresh materialized view concurrently public.stats_accuracy_by_team_alltime;
  refresh materialized view concurrently public.stats_accuracy_by_weight_alltime;
  refresh materialized view concurrently public.group_pick_consensus;
  refresh materialized view concurrently public.stats_accuracy_by_line_side;
  refresh materialized view concurrently public.stats_pick_streaks;
  -- Per-user situational ATS base (#502): pick-grain classification (primetime / home-away /
  -- spread bucket / divisional) the "Your edge" panel reads via stats_situational_splits. Driven
  -- by the same pick_settlement rows every other per-user stat is, so this is its refresh point.
  refresh materialized view concurrently public.stats_situational_base;
  -- Two-sided per-user team book (#564): backed + faded ATS records per team, season + all-time.
  -- Driven by the same pick_settlement rows every other per-user stat is, so this is its refresh
  -- point. Backed rows duplicate stats_accuracy_by_team's numbers; the fade side is net-new.
  refresh materialized view concurrently public.stats_team_book;
  refresh materialized view concurrently public.stats_team_book_alltime;
  -- League-wide team ATS facts (#406). Group-independent and driven by games/game_lines
  -- rather than pick_settlement, but the same grading run that settles picks is also when
  -- games go final + closing lines are captured, so this is the correct invalidation point.
  refresh materialized view concurrently public.league_ats_base;
end;
$$;

comment on function public.refresh_leaderboard_stats() is
  'Refreshes the 16 leaderboard/stats materialized views CONCURRENTLY (issues #191/#280/#294/#296/#317/#406/#502/#564). '
  'Called after each grading run by src/lib/server/grading.ts.';
